def load_session(session_id: str) -> Session | None:
    raw = r.get(meta_key(session_id))
    if raw is None:
        return None
    data = json.loads(raw)
    return Session(**data)

def touch_session(session_id: str) -> None:
    """Reset TTL and update last_active timestamp on activity."""
    session = load_session(session_id)
    if session is None:
        return
    session.last_active = time.time()
    r.set(meta_key(session_id), json.dumps(asdict(session)), ex=META_TTL)
    r.expire(msgs_key(session_id), SESSION_TTL)   # reset message history TTL too

def require_session(session_id: str, tenant_id: str, user_id: str) -> Session:
    session = load_session(session_id)
    if session is None:
        raise HTTPException(status_code=404, detail="Session not found or expired")
    if session.tenant_id != tenant_id or session.user_id != user_id:
        raise HTTPException(status_code=403, detail="Session does not belong to this user")
    touch_session(session_id)
    return session

from anthropic import Anthropic

client = Anthropic()

AGENT_CONFIGS = {
    "triage": {
        "system": "You are a triage agent. Understand the user's problem and decide if it needs a specialist.",
        "tools": [],  # no tools — pure conversation
    },
    "specialist": {
        "system": "You are a specialist agent with deep knowledge. Use tools to resolve the user's issue.",
        "tools": [
            {
                "name": "lookup_ticket",
                "description": "Look up a support ticket by ID.",
                "input_schema": {"type": "object", "properties": {"ticket_id": {"type": "string"}}, "required": ["ticket_id"]},
            }
        ],
    },
}

def chat_with_agent(session_id: str, tenant_id: str, user_id: str,
                     message: str, agent_type: str = "triage") -> dict:
    """Chat with a specific agent type while maintaining the same session."""
    session, messages = resume_session(session_id, tenant_id, user_id)
    config = AGENT_CONFIGS[agent_type]

    messages.append({"role": "user", "content": message})
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=600,
        system=config["system"],
        tools=config["tools"] or None,
        messages=messages,
    )
    assistant_content = [b.model_dump() if hasattr(b, "model_dump") else b for b in resp.content]
    messages.append({"role": "assistant", "content": assistant_content})

    # Persist updated history under the same session_id
    r.set(msgs_key(session_id), json.dumps(messages), ex=SESSION_TTL)
    touch_session(session_id)

    # If triage decides to hand off, update session metadata
    text = next((b["text"] for b in assistant_content if b.get("type") == "text"), "")
    if "specialist" in text.lower() and agent_type == "triage":
        update_session_metadata(session_id, {"escalated_to": "specialist"})

    return {"response": text, "agent": agent_type, "turns": len(messages) // 2}
